from typing import List

def solve(s: str, order: List[int], k: int) -> int:
    n = len(s)
    replaced = [False] * n  # Track replaced characters
    total_valid = 0  # Total number of valid substrings

    def count_valid_substrings():
        nonlocal total_valid
        total_valid = 0
        stars = []
        for i in range(n):
            if replaced[i]:
                stars.append(i)
        # Calculate number of valid substrings
        # Each star contributes (i) * (n - i) valid substrings
        for i in stars:
            total_valid += i * (n - i)
        # Also, each pair of stars contributes (j - i - 1) valid substrings
        for i in range(len(stars)):
            for j in range(i + 1, len(stars)):
                total_valid += stars[j] - stars[i] - 1

    for t in range(n):
        idx = order[t]
        replaced[idx] = True
        count_valid_substrings()
        if total_valid >= k:
            return t
    return -1
